1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { op: "quote"; items: Item[] };
13	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
14	
15	const quotePremium = (items: Item[]): number => {
16	  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
17	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
18	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
19	};
20	
21	export const runScenario = (input: unknown): unknown => {
22	  const scenario = input as Scenario;
23	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
24	  return { results };
25	};
